#include <bits/stdc++.h>
using namespace std;

int n, m, c[100005], a[100005];
int maxc = -10005;

int main() {
    cin >> n >> m;
    for (int i = 0; i < n; i++) {
        cin >> c[i];
        maxc = max(maxc, c[i]);
    }
    for (int i = 0; i < m; i++) {
        cin >> a[i];
        if (n == 1) maxc += a[i];
    }
    if (n == 1) cout << maxc;
    else {
        for (int i = 0; i < m; i++) {
            if (a[i] > 0) maxc += a[i];
        }
        cout << maxc;
    }
    return 0;
}
